code = """import json

k1 = 'var_function-call-17981552509113141854'
k2 = 'var_function-call-3218142005520764474'
f1 = locals().get(k1)
f2 = locals().get(k2)

with open(f1) as fo:
    d1 = json.load(fo)
with open(f2) as fo:
    d2 = json.load(fo)

s2 = set(d2)
syms = [x for x in d1 if x['Symbol'] in s2]
keywords = ["Ultra", "ProShares", "Direxion", "VelocityShares", "Bear", "Bull", "2x", "3x", "VIX", "Leveraged", "Inverse"]
candidates = set()
for x in syms:
    desc = x.get('Company Description', '')
    name = x.get('Symbol', '')
    if any(k.lower() in desc.lower() for k in keywords) or any(k.lower() in name.lower() for k in keywords):
        candidates.add(x['Symbol'])
majors = {'SPY', 'IVV', 'VOO', 'IWM', 'DIA', 'GLD'}
relevant_majors = {s for s in majors if s in [x['Symbol'] for x in syms]}
candidates.update(relevant_majors)

candidate_list = sorted(list(candidates))
batch = candidate_list[75:150]

sq = chr(39)
dq = chr(34)
qs = []
for s in batch:
    q = "(SELECT " + sq + s + sq + " as S FROM " + dq + s + dq + " WHERE " + dq + "Adj Close" + dq + " > 200 AND Date LIKE " + sq + "2015-%" + sq + " LIMIT 1)"
    qs.append(q)

res = " UNION ALL ".join(qs)
print('__RESULT__:')
print(json.dumps(res))"""

